select * from mh_user_favorite_popsci
where user_id = #{userId}
and popsci_id = #{popsciId}

SELECT popsci_id FROM mh_user_favorite_popsci
WHERE user_id = #{userId}


    AND favorite_type = #{dto.favoriteType}



    AND mushroom_id = #{dto.mushroomId}

SELECT c.id, c.content_type as contentType, c.title, u.username as authorName, c.publish_date as publishDate, c.description, m.mushroom_name as mushroomName, -- 取第一个图片作为封面（图文/视频区分） (SELECT p.pic_url FROM mh_picture p WHERE p.content_id = c.id AND p.type = '图文详情图' LIMIT 1) as articleCoverUrl, (SELECT p.pic_url FROM mh_picture p WHERE p.content_id = c.id AND p.type = '视频封面' LIMIT 1) as videoCoverUrl FROM mh_popsci_content c LEFT JOIN mh_user u ON c.author_id = u.user_id LEFT JOIN mh_mushroom_info m ON c.mushroom_id = m.id WHERE c.id IN
#{id}
AND c.content_status = 2 -- 仅审核通过 ORDER BY c.publish_date DESC
